'use client';

import React, { useState, useEffect } from 'react';
import { FiX, FiInfo, FiImage } from 'react-icons/fi';
import { useAppDispatch, useAppSelector } from '@/lib/hooks';
import { updateAboutSettings } from '@/lib/slices/contentSlice';
import ImageUpload from '@/components/ImageUpload';
import { useTranslation } from '@/hooks/useTranslation';

interface AboutAuthenticityEditorModalProps {
    onClose: () => void;
    onUpdate: () => void;
}

export default function AboutAuthenticityEditorModal({ onClose, onUpdate }: AboutAuthenticityEditorModalProps) {
    const { t } = useTranslation();
    const dispatch = useAppDispatch();
    const { aboutSettings } = useAppSelector((state) => state.content);

    const initialAuth = aboutSettings?.authenticity || {
        isVisible: true,
        tagline: 'ALCEIX CRAFTSMANSHIP',
        titlePart1: 'Captured in',
        titlePart2: 'the Alceix Moment',
        description: '"Beauty is not just in the final Alceix piece, but in the meticulous journey of its creation."',
        imageUrl: '/image/alceix/product.png',
        buttonText: 'Behind the Alceix scenes',
        layout: 'image-right',
    };

    const [settings, setSettings] = useState(initialAuth);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (aboutSettings?.authenticity) {
            setSettings(aboutSettings.authenticity);
        }
    }, [aboutSettings]);

    const handleSave = async () => {
        if (!aboutSettings) return;
        setIsSaving(true);
        try {
            await dispatch(updateAboutSettings({
                ...aboutSettings,
                authenticity: settings
            })).unwrap();
            onUpdate();
            onClose();
        } catch (err) {
            alert(t('admin.saveError'));
        } finally {
            setIsSaving(false);
        }
    };

    const layoutOptions = [
        {
            id: 'image-right',
            label: t('admin.aboutAuthenticityEditor.layouts.right'),
            desc: t('admin.aboutAuthenticityEditor.layouts.rightDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex gap-2 p-2 border border-border">
                    <div className="w-1/2 h-full flex flex-col justify-center gap-1.5">
                        <div className="w-1/2 h-1 bg-gray-300 rounded"></div>
                        <div className="w-full h-2 bg-gray-400 rounded"></div>
                        <div className="w-3/4 h-2 bg-gray-400 rounded"></div>
                        <div className="w-4 h-1 bg-[#C5A059] mt-1"></div>
                    </div>
                    <div className="w-1/2 h-full bg-gray-300 rounded overflow-hidden relative"></div>
                </div>
            )
        },
        {
            id: 'image-left',
            label: t('admin.aboutAuthenticityEditor.layouts.left'),
            desc: t('admin.aboutAuthenticityEditor.layouts.leftDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex flex-row-reverse gap-2 p-2 border border-border">
                    <div className="w-1/2 h-full flex flex-col justify-center gap-1.5">
                        <div className="w-1/2 h-1 bg-gray-300 rounded"></div>
                        <div className="w-full h-2 bg-gray-400 rounded"></div>
                        <div className="w-3/4 h-2 bg-gray-400 rounded"></div>
                        <div className="w-4 h-1 bg-[#C5A059] mt-1"></div>
                    </div>
                    <div className="w-1/2 h-full bg-gray-300 rounded overflow-hidden relative"></div>
                </div>
            )
        },
        {
            id: 'stacked',
            label: t('admin.aboutAuthenticityEditor.layouts.stacked'),
            desc: t('admin.aboutAuthenticityEditor.layouts.stackedDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex flex-col gap-2 p-2 border border-border">
                    <div className="w-full flex-1 flex flex-col items-center justify-center gap-1">
                        <div className="w-1/4 h-1 bg-gray-300 rounded"></div>
                        <div className="w-1/2 h-2 bg-gray-400 rounded"></div>
                    </div>
                    <div className="w-full h-8 bg-gray-300 rounded overflow-hidden relative"></div>
                </div>
            )
        }
    ];

    return (
        <div className="fixed inset-0 bg-foreground/50 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
            <div className="bg-background rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                <div className="flex items-center justify-between p-6 border-b border-border">
                    <div>
                        <h2 className="text-xl font-bold">{t('admin.aboutAuthenticityEditor.title')}</h2>
                        <p className="text-xs text-muted-foreground mt-1">{t('admin.aboutAuthenticityEditor.subtitle')}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-muted/80 rounded-full transition-colors">
                        <FiX size={20} />
                    </button>
                </div>

                <div className="p-6 max-h-[70vh] overflow-y-auto">
                    {/* Layout Selector */}
                    <div className="pb-6 border-b border-border mb-6">
                        <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-4">{t('admin.aboutAuthenticityEditor.chooseLayout')}</label>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            {layoutOptions.map(opt => (
                                <button
                                    key={opt.id}
                                    onClick={() => setSettings({ ...settings, layout: opt.id as any })}
                                    className={`flex flex-col p-3 text-left rounded-xl border-2 transition-all group ${settings.layout === opt.id ? 'border-foreground bg-foreground text-background shadow-lg' : 'border-border hover:border-border text-muted-foreground bg-background'}`}
                                >
                                    <div className="mb-3 transition-transform group-hover:scale-[1.02]">
                                        {opt.preview}
                                    </div>
                                    <span className="font-bold text-[10px] uppercase tracking-wider mb-1">{opt.label}</span>
                                    <p className={`text-[9px] leading-tight ${settings.layout === opt.id ? 'text-gray-300' : 'text-muted-foreground/80'}`}>{opt.desc}</p>
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="col-span-2">
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutAuthenticityEditor.tagline')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.tagline}
                                onChange={(e) => setSettings({ ...settings, tagline: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutAuthenticityEditor.titlePart1')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.titlePart1}
                                onChange={(e) => setSettings({ ...settings, titlePart1: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutAuthenticityEditor.titlePart2')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.titlePart2}
                                onChange={(e) => setSettings({ ...settings, titlePart2: e.target.value })}
                            />
                        </div>

                        <div className="col-span-2">
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutAuthenticityEditor.description')}</label>
                            <textarea
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors h-24 resize-none"
                                value={settings.description}
                                onChange={(e) => setSettings({ ...settings, description: e.target.value })}
                            />
                        </div>

                        <div className="col-span-2">
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutAuthenticityEditor.imageUpload')}</label>
                            <div className="p-1 bg-muted rounded-xl border border-border flex justify-center">
                                <ImageUpload
                                    value={settings.imageUrl}
                                    onChange={(url) => setSettings({ ...settings, imageUrl: url })}
                                />
                            </div>
                        </div>

                        <div className="col-span-2">
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutAuthenticityEditor.buttonText')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.buttonText}
                                onChange={(e) => setSettings({ ...settings, buttonText: e.target.value })}
                            />
                        </div>
                    </div>
                </div>

                <div className="p-6 border-t border-border bg-muted flex justify-end gap-3">
                    <button onClick={onClose} className="px-6 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground transition-colors" disabled={isSaving}>{t('admin.cancel')}</button>
                    <button onClick={handleSave} disabled={isSaving} className="px-6 py-2.5 bg-foreground text-background text-sm font-bold rounded-lg hover:bg-gray-800 transition-colors disabled:opacity-50">
                        {isSaving ? t('admin.saving') : t('admin.save')}
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { FiX, FiInfo } from 'react-icons/fi';
import { useAppDispatch, useAppSelector } from '@/lib/hooks';
import { updateAboutSettings } from '@/lib/slices/contentSlice';
import VideoUpload from '@/components/VideoUpload';
import { useTranslation } from '@/hooks/useTranslation';

interface AboutHeroEditorModalProps {
    onClose: () => void;
    onUpdate: () => void;
}

export default function AboutHeroEditorModal({ onClose, onUpdate }: AboutHeroEditorModalProps) {
    const { t } = useTranslation();
    const dispatch = useAppDispatch();
    const { aboutSettings } = useAppSelector((state) => state.content);

    const initialHero = aboutSettings?.hero || {
        isVisible: true,
        title: 'Our Alceix Story',
        subtitle: 'The Essence of Alceix Elegance',
        videoUrl: '',
        layout: 'fullscreen',
    };

    const [settings, setSettings] = useState(initialHero);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (aboutSettings?.hero) {
            setSettings(aboutSettings.hero);
        }
    }, [aboutSettings]);

    const handleSave = async () => {
        if (!aboutSettings) return;
        setIsSaving(true);
        try {
            await dispatch(updateAboutSettings({
                ...aboutSettings,
                hero: settings
            })).unwrap();
            onUpdate();
            onClose();
        } catch (err) {
            alert(t('admin.saveError'));
        } finally {
            setIsSaving(false);
        }
    };

    const layoutOptions = [
        {
            id: 'fullscreen',
            label: t('admin.aboutHeroEditor.layouts.fullscreen'),
            desc: t('admin.aboutHeroEditor.layouts.fullscreenDesc'),
            preview: (
                <div className="w-full h-20 bg-gray-200 rounded-lg flex items-center justify-center relative overflow-hidden">
                    <div className="w-full h-full bg-gray-300 absolute inset-0"></div>
                    <div className="w-16 h-2 bg-foreground/40 rounded-full z-10 mb-2"></div>
                    <div className="w-24 h-4 bg-foreground/60 rounded-full z-10 absolute"></div>
                </div>
            )
        },
        {
            id: 'split-visual',
            label: t('admin.aboutHeroEditor.layouts.split'),
            desc: t('admin.aboutHeroEditor.layouts.splitDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex border border-border overflow-hidden">
                    <div className="w-1/2 h-full bg-gray-300"></div>
                    <div className="w-1/2 h-full flex flex-col items-center justify-center gap-1.5 p-2">
                        <div className="w-8 h-1.5 bg-gray-300 rounded-full"></div>
                        <div className="w-14 h-2.5 bg-gray-400 rounded-full"></div>
                    </div>
                </div>
            )
        },
        {
            id: 'minimal-centered',
            label: t('admin.aboutHeroEditor.layouts.minimal'),
            desc: t('admin.aboutHeroEditor.layouts.minimalDesc'),
            preview: (
                <div className="w-full h-20 bg-background rounded-lg border border-border flex flex-col items-center justify-center gap-2 p-2 relative">
                    <div className="w-full h-10 bg-gray-200 rounded"></div>
                    <div className="w-12 h-2.5 bg-gray-400 rounded-full absolute top-1/2 -translate-y-1/2 left-1/2 -translate-x-1/2"></div>
                </div>
            )
        }
    ];

    return (
        <div className="fixed inset-0 bg-foreground/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-background rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                <div className="flex items-center justify-between p-6 border-b border-border">
                    <div>
                        <h2 className="text-xl font-bold">{t('admin.aboutHeroEditor.title')}</h2>
                        <p className="text-xs text-muted-foreground mt-1">{t('admin.aboutHeroEditor.subtitle')}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-muted/80 rounded-full transition-colors">
                        <FiX size={20} />
                    </button>
                </div>

                <div className="p-6 max-h-[70vh] overflow-y-auto">
                    {/* Layout Selector */}
                    <div className="pb-6 border-b border-border mb-6">
                        <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-4">{t('admin.aboutHeroEditor.chooseLayout')}</label>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            {layoutOptions.map(opt => (
                                <button
                                    key={opt.id}
                                    onClick={() => setSettings({ ...settings, layout: opt.id as any })}
                                    className={`flex flex-col p-3 text-left rounded-xl border-2 transition-all group ${settings.layout === opt.id ? 'border-foreground bg-foreground text-background shadow-lg' : 'border-border hover:border-border text-muted-foreground bg-background'}`}
                                >
                                    <div className="mb-3 transition-transform group-hover:scale-[1.02]">
                                        {opt.preview}
                                    </div>
                                    <span className="font-bold text-[10px] uppercase tracking-wider mb-1">{opt.label}</span>
                                    <p className={`text-[9px] leading-tight ${settings.layout === opt.id ? 'text-gray-300' : 'text-muted-foreground/80'}`}>{opt.desc}</p>
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Content Fields */}
                    <div className="space-y-4">
                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutHeroEditor.titleLabel')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.title}
                                onChange={(e) => setSettings({ ...settings, title: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutHeroEditor.subtitleLabel')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.subtitle}
                                onChange={(e) => setSettings({ ...settings, subtitle: e.target.value })}
                            />
                            <p className="text-[10px] text-muted-foreground mt-1.5 flex items-center gap-1">
                                <FiInfo size={12} /> {t('admin.aboutHeroEditor.subtitleHint')}
                            </p>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutHeroEditor.videoUpload')}</label>
                            <VideoUpload
                                value={settings.videoUrl}
                                onChange={(url) => setSettings({ ...settings, videoUrl: url })}
                            />
                        </div>
                    </div>
                </div>

                <div className="p-6 border-t border-border bg-muted flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-6 py-2.5 text-sm font-bold text-muted-foreground hover:text-foreground transition-colors"
                        disabled={isSaving}
                    >
                        {t('admin.cancel')}
                    </button>
                    <button
                        onClick={handleSave}
                        disabled={isSaving}
                        className="px-6 py-2.5 bg-foreground text-background text-sm font-bold rounded-lg hover:bg-gray-800 transition-colors disabled:opacity-50"
                    >
                        {isSaving ? t('admin.saving') : t('admin.save')}
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { FiX, FiInfo, FiImage } from 'react-icons/fi';
import { useAppDispatch, useAppSelector } from '@/lib/hooks';
import { updateAboutSettings } from '@/lib/slices/contentSlice';
import ImageUpload from '@/components/ImageUpload';
import { useTranslation } from '@/hooks/useTranslation';

interface AboutPhilosophyEditorModalProps {
    onClose: () => void;
    onUpdate: () => void;
}

export default function AboutPhilosophyEditorModal({ onClose, onUpdate }: AboutPhilosophyEditorModalProps) {
    const { t } = useTranslation();
    const dispatch = useAppDispatch();
    const { aboutSettings } = useAppSelector((state) => state.content);

    const initialPhilosophy = aboutSettings?.philosophy || {
        isVisible: true,
        quote: '"Real elegance is found in the Alceix craftsmanship."',
        imageUrl: '/image/alceix/product.png',
        tagline: 'ALCEIX PHILOSOPHY',
        backgroundText: 'Alceix',
        layout: 'centered-quote',
    };

    const [settings, setSettings] = useState(initialPhilosophy);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (aboutSettings?.philosophy) {
            setSettings(aboutSettings.philosophy);
        }
    }, [aboutSettings]);

    const handleSave = async () => {
        if (!aboutSettings) return;
        setIsSaving(true);
        try {
            await dispatch(updateAboutSettings({
                ...aboutSettings,
                philosophy: settings
            })).unwrap();
            onUpdate();
            onClose();
        } catch (err) {
            alert(t('admin.saveError'));
        } finally {
            setIsSaving(false);
        }
    };

    const layoutOptions = [
        {
            id: 'centered-quote',
            label: t('admin.aboutPhilosophyEditor.layouts.centered'),
            desc: t('admin.aboutPhilosophyEditor.layouts.centeredDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex flex-col items-center justify-center gap-1 p-2 border border-border">
                    <div className="w-6 h-6 rounded-full bg-gray-300"></div>
                    <div className="w-3/4 h-2 bg-gray-400 rounded-sm"></div>
                    <div className="w-1/2 h-2 bg-gray-400 rounded-sm"></div>
                    <div className="w-8 h-1 bg-[#C5A059] mt-1"></div>
                </div>
            )
        },
        {
            id: 'left-aligned',
            label: t('admin.aboutPhilosophyEditor.layouts.left'),
            desc: t('admin.aboutPhilosophyEditor.layouts.leftDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex items-center justify-between gap-2 p-2 border border-border">
                    <div className="w-2/3 flex flex-col gap-1">
                        <div className="w-full h-2 bg-gray-400 rounded-sm"></div>
                        <div className="w-4/5 h-2 bg-gray-400 rounded-sm"></div>
                        <div className="w-8 h-1 bg-[#C5A059] mt-1"></div>
                    </div>
                    <div className="w-8 h-8 rounded-full bg-gray-300"></div>
                </div>
            )
        },
        {
            id: 'quote-focus',
            label: t('admin.aboutPhilosophyEditor.layouts.quoteFocus'),
            desc: t('admin.aboutPhilosophyEditor.layouts.quoteFocusDesc'),
            preview: (
                <div className="w-full h-20 bg-muted rounded-lg flex flex-col items-center justify-center gap-1 p-2 border border-border relative overflow-hidden">
                    <div className="w-24 h-4 bg-gray-200 rounded-sm absolute opacity-30"></div>
                    <div className="w-full h-3 bg-gray-400 rounded-sm z-10"></div>
                    <div className="w-2/3 h-3 bg-gray-400 rounded-sm z-10"></div>
                </div>
            )
        }
    ];

    return (
        <div className="fixed inset-0 bg-foreground/50 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
            <div className="bg-background rounded-2xl w-full max-w-2xl overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                <div className="flex items-center justify-between p-6 border-b border-border">
                    <div>
                        <h2 className="text-xl font-bold">{t('admin.aboutPhilosophyEditor.title')}</h2>
                        <p className="text-xs text-muted-foreground mt-1">{t('admin.aboutPhilosophyEditor.subtitle')}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-muted/80 rounded-full transition-colors">
                        <FiX size={20} />
                    </button>
                </div>

                <div className="p-6 max-h-[70vh] overflow-y-auto">
                    {/* Layout Selector */}
                    <div className="pb-6 border-b border-border mb-6">
                        <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-4">{t('admin.aboutPhilosophyEditor.chooseLayout')}</label>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            {layoutOptions.map(opt => (
                                <button
                                    key={opt.id}
                                    onClick={() => setSettings({ ...settings, layout: opt.id as any })}
                                    className={`flex flex-col p-3 text-left rounded-xl border-2 transition-all group ${settings.layout === opt.id ? 'border-foreground bg-foreground text-background shadow-lg' : 'border-border hover:border-border text-muted-foreground bg-background'}`}
                                >
                                    <div className="mb-3 transition-transform group-hover:scale-[1.02]">
                                        {opt.preview}
                                    </div>
                                    <span className="font-bold text-[10px] uppercase tracking-wider mb-1">{opt.label}</span>
                                    <p className={`text-[9px] leading-tight ${settings.layout === opt.id ? 'text-gray-300' : 'text-muted-foreground/80'}`}>{opt.desc}</p>
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutPhilosophyEditor.quoteTagline')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.tagline}
                                onChange={(e) => setSettings({ ...settings, tagline: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutPhilosophyEditor.philosophyQuote')}</label>
                            <textarea
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors h-24 resize-none"
                                value={settings.quote}
                                onChange={(e) => setSettings({ ...settings, quote: e.target.value })}
                            />
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutPhilosophyEditor.centerImage')}</label>
                            <div className="p-1 bg-muted rounded-xl border border-border flex justify-center max-w-[200px]">
                                <ImageUpload
                                    value={settings.imageUrl}
                                    onChange={(url) => setSettings({ ...settings, imageUrl: url })}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-foreground/80 uppercase tracking-wider mb-2">{t('admin.aboutPhilosophyEditor.backgroundText')}</label>
                            <input
                                type="text"
                                className="w-full px-4 py-2 border border-border rounded-lg focus:outline-none focus:border-foreground transition-colors"
                                value={settings.backgroundText}
