'use client';

import { useState, useEffect } from 'react';
import { useAppDispatch, useAppSelector } from '@/lib/hooks';
import { updateHomeSettings, updateProductSettings } from '@/lib/slices/contentSlice';
import { Advantage } from '@/types/content';
import { FiLayout, FiX, FiCheck, FiPlus, FiTrash2, FiSave, FiTag, FiTruck, FiBox, FiShield, FiHeart, FiGift, FiAward, FiClock, FiSmartphone, FiCreditCard } from 'react-icons/fi';
import { useTranslation } from '@/hooks/useTranslation';

const AVAILABLE_ICONS = [
    { name: 'FiTruck', icon: FiTruck },
    { name: 'FiBox', icon: FiBox },
    { name: 'FiShield', icon: FiShield },
    { name: 'FiHeart', icon: FiHeart },
    { name: 'FiGift', icon: FiGift },
    { name: 'FiAward', icon: FiAward },
    { name: 'FiClock', icon: FiClock },
    { name: 'FiSmartphone', icon: FiSmartphone },
    { name: 'FiCreditCard', icon: FiCreditCard },
    { name: 'FiTag', icon: FiTag },
];

import { updateComponentInstance } from '@/lib/slices/componentSlice';

export default function AdvantageSectionEditorModal({ onClose, onUpdate, isProductPage, instanceId }: { onClose: () => void; onUpdate: () => void; isProductPage?: boolean; instanceId?: string } | any) {
    const { t } = useTranslation();
    const dispatch = useAppDispatch();
    const { homeSettings, productSettings } = useAppSelector((state) => state.content);
    const { instances } = useAppSelector((state) => state.component);

    const instance = instanceId ? instances.find(i => i._id === instanceId) : null;

    const [settings, setSettings] = useState(homeSettings?.advantageSection || { isVisible: true, title: 'Why Choose Us', advantages: [] });
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (instanceId && instance) {
            setSettings(instance.data || { isVisible: true, title: '', advantages: [] });
        } else if (homeSettings?.advantageSection) {
            setSettings(homeSettings.advantageSection);
        }
    }, [homeSettings, instance, instanceId]);

    const handleSave = async () => {
        setIsSaving(true);
        try {
            if (instanceId) {
                await dispatch(updateComponentInstance({
                    id: instanceId,
                    data: settings
                })).unwrap();
            } else if (homeSettings) {
                await dispatch(updateHomeSettings({
                    ...homeSettings,
                    advantageSection: settings
                })).unwrap();
            }

            // Trigger refresh and close
            onUpdate();
            alert(t('admin.saveSuccess'));
            onClose();
        } catch (e) {
            alert(t('admin.saveError'));
        } finally {
            setIsSaving(false);
        }
    };

    const addAdvantage = () => {
        const newAdv: Advantage = {
            id: Date.now().toString(),
            title: 'New Advantage',
            description: 'Enter description here',
            icon: 'FiTruck'
        };
        setSettings({ ...settings, advantages: [...settings.advantages, newAdv] });
    };

    const updateAdvantage = (id: string, updates: Partial<Advantage>) => {
        setSettings({
            ...settings,
            advantages: settings.advantages.map(a => a.id === id ? { ...a, ...updates } : a)
        });
    };

    const removeAdvantage = (id: string) => {
        setSettings({
