                                        <label className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground/80">{t('admin.campaignEditor.cardImage')}</label>
                                        <ImageUpload
                                            value={item.image}
                                            onChange={(url) => updateItem(item.id, { image: url })}
