        title: instance?.data?.title || 'Legal Information',
        content: instance?.data?.content || '<p>Enter your content here...</p>',
        variant: instance?.data?.variant || 'standard'
    });

    const editor = useEditor({
        extensions: [
            StarterKit,
            Link.configure({ openOnClick: false }),
        ],
        immediatelyRender: false,
        content: formData.content,
        onUpdate: ({ editor }) => {
            setFormData(prev => ({ ...prev, content: editor.getHTML() }));
        },
        editorProps: {
            attributes: {
                class: 'prose prose-sm sm:prose-base dark:prose-invert focus:outline-none min-h-[400px] p-8 max-w-none transition-colors border-none',
            },
        },
    });

