import { fetchGlobalSettings } from '@/lib/slices/contentSlice'; // Import fetch action
import {
  FiGrid, FiBox, FiTag, FiLayout, FiUsers, FiLogOut,
  FiShoppingBag, FiBook, FiMail, FiMenu, FiX,
  FiSearch, FiBell, FiChevronLeft, FiChevronRight,
  FiSettings, FiHelpCircle, FiCreditCard
} from 'react-icons/fi';
import { useTranslation } from '@/hooks/useTranslation';

import { motion, AnimatePresence } from 'framer-motion';

// Menu Configuration

export default function AdminLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const { t } = useTranslation();
  const router = useRouter();
  const dispatch = useAppDispatch();
  const pathname = usePathname();

  // Menu Configuration
  const MENU_GROUPS = [
    {
      title: t('admin.menu.overview'),
      items: [
        { href: '/admin', label: t('admin.menu.dashboard'), icon: FiGrid }
      ]
    },
    {
      title: t('admin.menu.ecommerce'),
      items: [
        { href: '/admin/products', label: t('admin.menu.products'), icon: FiBox },
        { href: '/admin/orders', label: t('admin.menu.orders'), icon: FiShoppingBag },
        { href: '/admin/categories', label: t('admin.menu.categories'), icon: FiTag },
        { href: '/admin/coupons', label: t('admin.menu.coupons'), icon: FiTag },
      ]
    },
    {
      title: t('admin.menu.content'),
      items: [
        { href: '/admin/journal', label: t('admin.menu.journal'), icon: FiBook },
        { href: '/admin/layout-settings', label: t('admin.menu.layout'), icon: FiLayout },
        { href: '/admin/messages', label: t('admin.menu.messages'), icon: FiMail },
      ]
    },
    {
      title: t('admin.menu.management'),
      items: [
        { href: '/admin/users', label: t('admin.menu.users'), icon: FiUsers },
        { href: '/admin/settings/payment', label: t('admin.menu.payment'), icon: FiCreditCard },
      ]
    }
  ];

  const { isAuthenticated, user, isVerifying } = useAppSelector((state) => state.auth);
  const { globalSettings, hasLoadedOnce } = useAppSelector((state) => state.content); // Get global settings

  const [mounted, setMounted] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true); // Desktop toggle
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // Mobile toggle

  useEffect(() => {
    setMounted(true);
    if (!hasLoadedOnce) {
      dispatch(fetchGlobalSettings());
    }
  }, [dispatch, hasLoadedOnce]);

  useEffect(() => {
    if (!mounted || isVerifying) return;

    if (!isAuthenticated) {
      router.push('/login');
      return;
    }

    if (user?.role !== 'admin') {
      router.push('/');
      return;
    }
  }, [mounted, isAuthenticated, user, router, isVerifying]);

  // Handle screen resize to auto-close/open sidebar
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 1024) {
        setIsSidebarOpen(false);
      } else {
        setIsSidebarOpen(true);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Auto-collapse sidebar in Layout Settings
  useEffect(() => {
    if (pathname === '/admin/layout-settings') {
      setIsSidebarOpen(false);
    }
  }, [pathname]);

  if (!mounted || isVerifying) {
     return (
        <div className="flex h-screen items-center justify-center bg-background">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-foreground mx-auto"></div>
        </div>
     );
  }

  if (!isAuthenticated || user?.role !== 'admin') {
    return null;
  }

  // If we are authenticated but user role is not yet confirmed (edge case) or still loading initial settings
  if (!user || user.role !== 'admin') {
     return (
        <div className="flex h-screen items-center justify-center bg-background">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-foreground mx-auto"></div>
        </div>
     );
  }

  const handleLogout = async () => {
    await dispatch(logoutUser());
    dispatch(clearProfile());
    router.replace('/login');
  };

  return (
    <div className="min-h-screen bg-background flex text-foreground font-sans overflow-hidden">

      {/* Mobile Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setIsMobileMenuOpen(false)}
            className="fixed inset-0 bg-foreground/50 z-40 lg:hidden backdrop-blur-sm"
          />
        )}
      </AnimatePresence>

      {/* Sidebar Navigation */}
      <motion.aside
        initial={false}
        animate={{
          width: isSidebarOpen ? 280 : 80,
          translateX: isMobileMenuOpen ? 0 : (window.innerWidth < 1024 ? -280 : 0)
        }}
        transition={{ duration: 0.3, ease: "easeInOut" }}
        className={`fixed lg:relative inset-y-0 left-0 bg-background border-r border-foreground/10 z-50 flex flex-col h-screen shadow-xl lg:shadow-none
          ${!isMobileMenuOpen && 'hidden lg:flex'}
        `}
      >
        {/* Logo Section */}
        <div className="h-16 flex items-center px-6 border-b border-foreground/5 justify-between relative group">
          <Link href="/" className={`flex items-center gap-3 overflow-hidden ${!isSidebarOpen && 'justify-center w-full px-0'}`}>
            {globalSettings?.logo ? (
              <div className="w-8 h-8 rounded-lg relative overflow-hidden shrink-0">
                <img src={globalSettings.logo} alt={t('admin.menu.logo')} className="w-full h-full object-cover" />
              </div>
            ) : (
              <div className="w-8 h-8 rounded-lg bg-foreground text-background flex items-center justify-center font-serif font-bold shrink-0">
                {globalSettings?.siteName?.charAt(0) || 'A'}
              </div>
            )}

            {isSidebarOpen && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="font-serif font-medium text-lg whitespace-nowrap"
              >
                {globalSettings?.siteName || 'Alceix Group'}
              </motion.div>
            )}
          </Link>

          {/* Collapse Toggle Button (Desktop Only) - Moved Here */}
          <button
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="absolute -right-3 top-[44px] lg:flex hidden items-center justify-center w-6 h-6 bg-background border border-foreground/10 rounded-full shadow-md text-foreground/50 hover:text-foreground hover:scale-110 transition-all z-50 cursor-pointer"
            title={isSidebarOpen ? t('admin.menu.collapse') : t('admin.menu.expand')}
          >
            {isSidebarOpen ? <FiChevronLeft size={14} /> : <FiChevronRight size={14} />}
          </button>

          {/* Close button for mobile */}
          <button
            onClick={() => setIsMobileMenuOpen(false)}
            className="lg:hidden p-1 rounded-md hover:bg-foreground/5"
          >
            <FiX size={20} />
          </button>
        </div>

        {/* Navigation Items */}
        <div className="flex-1 overflow-y-auto overflow-x-hidden py-6 px-3 custom-scrollbar">
          {MENU_GROUPS.map((group, groupIndex) => (
            <div key={group.title} className={`mb-6 ${!isSidebarOpen && 'text-center'}`}>
              {isSidebarOpen && (
                <div className="px-3 mb-2 text-[11px] font-bold text-foreground/40 uppercase tracking-wider">
                  {group.title}
                </div>
              )}
              {/* Separator for collapsed state */}
              {!isSidebarOpen && groupIndex > 0 && <div className="h-px bg-foreground/10 w-10 mx-auto my-4" />}

              <div className="space-y-1">
                {group.items.map((item) => {
                  const isActive = pathname === item.href || (item.href !== '/admin' && pathname.startsWith(item.href));
                  const Icon = item.icon;

                  return (
                    <Link
                      key={item.href}
                      href={item.href}
                      title={!isSidebarOpen ? item.label : ''}
                      className={`group flex items-center gap-3 px-3 py-2.5 rounded-2xl transition-all duration-200 font-medium text-sm
                        ${isActive
                          ? 'bg-foreground text-background shadow-lg shadow-foreground/10'
                          : 'text-foreground/50 hover:bg-background hover:shadow-sm hover:text-foreground'
                        }
                        ${!isSidebarOpen ? 'justify-center px-2' : ''}
                      `}
                    >
                      <Icon className={`w-5 h-5 shrink-0 ${isActive ? 'text-background' : 'text-foreground/40 group-hover:text-foreground/60'}`} />

                      {isSidebarOpen && (
                        <span className="text-sm font-medium whitespace-nowrap">{item.label}</span>
                      )}

                      {/* Floating tooltip for collapsed state */}
                      {!isSidebarOpen && (
                        <div className="absolute left-16 bg-foreground text-background text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 pointer-events-none transition-opacity z-50 whitespace-nowrap">
                          {item.label}
                        </div>
                      )}
                    </Link>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* User Profile Section */}
        <div className="p-4 border-t border-foreground/10 bg-foreground/5">

          <div className={`flex items-center gap-3 ${!isSidebarOpen ? 'justify-center' : ''}`}>
            <div className="w-9 h-9 rounded-full bg-foreground text-background flex items-center justify-center text-sm font-medium shrink-0 shadow-md">
              {user?.name?.[0] || 'A'}
            </div>

            {isSidebarOpen && (
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-foreground truncate">{user?.name}</p>
                <p className="text-xs text-foreground/50 truncate">{t('admin.menu.management')}</p>
              </div>
            )}

            {isSidebarOpen && (
              <button
                onClick={handleLogout}
                className="p-1.5 text-foreground/40 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-colors"
                title={t('admin.menu.logout')}
              >
                <FiLogOut size={18} />
              </button>
            )}
          </div>
        </div>
      </motion.aside>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden bg-background">

        {/* Top Header */}
        <header className="h-16 bg-background border-b border-foreground/10 flex items-center justify-between px-4 lg:px-8 z-20">
          <div className="flex items-center gap-4">
            <button
              onClick={() => window.innerWidth < 1024 ? setIsMobileMenuOpen(true) : setIsSidebarOpen(!isSidebarOpen)}
              className="p-2 hover:bg-foreground/5 rounded-lg text-foreground/60 transition-colors"
            >
              <FiMenu size={20} />
            </button>

            {/* Search Bar - Visual Only for now */}
            <div className="hidden md:flex items-center gap-2 px-3 py-2 bg-foreground/5 rounded-lg w-64 focus-within:ring-2 focus-within:ring-foreground/10 transition-all">
              <FiSearch className="text-foreground/40" />
              <input
                type="text"
                placeholder={t('admin.menu.search')}
                className="bg-transparent border-none outline-none text-sm w-full placeholder:text-foreground/40"
              />
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button className="p-2 relative hover:bg-foreground/5 rounded-lg text-foreground/60 transition-colors">
              <FiBell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-background"></span>
            </button>
            <button className="p-2 hover:bg-foreground/5 rounded-lg text-foreground/60 transition-colors">
              <FiHelpCircle size={20} />
            </button>
          </div>
        </header>

        {/* Scrollable Content */}
        <main className="flex-1 overflow-auto p-4 lg:p-8">
          <div className="max-w-7xl mx-auto space-y-6">
            {/* Breadcrumb / Title Area could go here */}
            {children}
          </div>
        </main>
      </div>

    </div>
  );
}

'use client'

import { useEffect } from 'react';
import { useAppDispatch, useAppSelector } from '@/lib/hooks';
import { fetchMessages } from '@/lib/slices/adminSlice';
import { FiMail, FiCalendar, FiUser, FiMessageSquare } from 'react-icons/fi';
import { useTranslation } from '@/hooks/useTranslation';

export default function MessagesPage() {
    const { t } = useTranslation();
    const dispatch = useAppDispatch();
    const { messages, loading, error } = useAppSelector((state) => state.admin);
    const isLoading = loading.fetchMessages;

    useEffect(() => {
        dispatch(fetchMessages());
    }, [dispatch]);

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-foreground"></div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="bg-red-500/10 text-red-500 p-4 rounded-xl border border-red-500/20 text-sm font-medium">
                {error}
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center bg-background p-6 rounded-2xl border border-foreground/10 shadow-sm">
                <h1 className="text-3xl font-bold text-foreground tracking-tight">{t('admin.communication.messages.title')}</h1>
                <div className="bg-foreground/5 px-4 py-2 rounded-lg border border-foreground/5 text-[10px] font-bold uppercase tracking-widest text-foreground/40">
                    {t('admin.communication.messages.total')}: {messages.length}
                </div>
            </div>

            <div className="grid gap-4">
                {messages.length === 0 ? (
                    <div className="text-center py-12 bg-background rounded-2xl border border-dashed border-foreground/20 text-foreground/30 font-bold uppercase tracking-widest text-[10px]">
                        <FiMail className="mx-auto h-12 w-12 opacity-20 mb-4" />
                        <p>{t('admin.communication.messages.empty')}</p>
                    </div>
                ) : (
                    messages.map((message) => (
                        <div
                            key={message._id}
                            className="bg-background p-6 rounded-2xl border border-foreground/10 hover:shadow-md transition-all cursor-pointer group hover:bg-foreground/[0.02]"
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-full bg-foreground text-background flex items-center justify-center font-bold uppercase text-sm border border-foreground/10 shadow-sm transition-transform group-hover:scale-105">
                                        {message.name.charAt(0)}
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-foreground group-hover:text-primary transition-colors">{message.subject}</h3>
                                        <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-wider text-foreground/40">
                                            <FiUser size={12} className="opacity-50" />
                                            <span>{message.name}</span>
                                            <span className="opacity-20">•</span>
                                            <span className="font-mono lowercase opacity-60 tracking-normal">{message.email}</span>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-foreground/30 bg-foreground/5 px-2.5 py-1.5 rounded-lg border border-foreground/5">
                                    <FiCalendar size={12} className="opacity-50" />
                                    <span>{new Date(message.createdAt).toLocaleDateString()}</span>
                                </div>
                            </div>

                            <div className="pl-13 ml-13">
                                <p className="text-foreground/60 text-sm leading-relaxed border-l-2 border-foreground/10 pl-4 font-medium italic">
                                    "{message.message}"
                                </p>
                            </div>

                            <div className="mt-4 flex justify-end">
                                <span className={`text-[10px] font-bold uppercase tracking-[0.2em] px-3 py-1.5 rounded-full border shadow-sm ${message.status === 'new'
                                    ? 'bg-green-500/10 text-green-500 border-green-500/20' :
                                    message.status === 'read'
                                        ? 'bg-foreground/5 text-foreground/40 border-foreground/10' :
                                        'bg-primary/10 text-primary border-primary/20'
                                    }`}>
                                    {t(`admin.communication.messages.status.${message.status}`)}
                                </span>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { FiSave, FiCreditCard, FiCheckCircle, FiAlertCircle, FiInfo, FiShield, FiGlobe, FiExternalLink } from 'react-icons/fi';
import { motion, AnimatePresence } from 'framer-motion';
import { paymentSettingsService } from '@/lib/services/paymentSettingsService';
import { PaymentSettings } from '@/types/payment-settings';
import { useTranslation } from '@/hooks/useTranslation';

export default function PaymentSettingsPage() {
    const { t } = useTranslation();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });

    const [settings, setSettings] = useState<PaymentSettings>({
        paypal: {
            active: false,
            clientId: '',
            clientSecret: '',
            mode: 'sandbox'
        },
        iyzico: {
            active: false,
            apiKey: '',
            secretKey: '',
            baseUrl: 'https://sandbox-api.iyzipay.com'
        },
        storeUrl: ''
    });

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        try {
            setLoading(true);
            const data = await paymentSettingsService.getPaymentSettings();
            setSettings(data);
        } catch (error: any) {
            console.error('Fetch settings error:', error);
            setMessage({ type: 'error', text: t('admin.management.payment.messages.error') });
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();

        // Validation
        if (settings.paypal?.active && (!settings.paypal.clientId || !settings.paypal.clientSecret)) {
            setMessage({ type: 'error', text: t('admin.management.payment.validation.paypalMissing') });
            return;
        }
        if (settings.iyzico?.active && (!settings.iyzico.apiKey || !settings.iyzico.secretKey)) {
            setMessage({ type: 'error', text: t('admin.management.payment.validation.iyzicoMissing') });
            return;
        }

        // Global Validation
        if (!settings.storeUrl) {
            setMessage({ type: 'error', text: t('admin.management.payment.validation.urlRequired') });
            return;
        }

        try {
            setSaving(true);
            setMessage({ type: '', text: '' });

            await paymentSettingsService.updatePaymentSettings(settings);

            setMessage({ type: 'success', text: t('admin.management.payment.messages.success') });
            // Re-fetch to see the masked values
            fetchSettings();
        } catch (error: any) {
            console.error('Update settings error:', error);
            setMessage({ type: 'error', text: t('admin.management.payment.messages.updateFailed') });
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-foreground mx-auto mb-4"></div>
            </div>
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Header */}
            <div>
                <h1 className="text-3xl font-bold text-foreground tracking-tight">{t('admin.management.payment.title')}</h1>
                <p className="text-foreground/50 mt-2">{t('admin.management.payment.subtitle')}</p>
            </div>

            {message.text && (
                <div className={`p-4 rounded-xl border flex items-center gap-3 text-sm font-medium ${
                    message.type === 'success' ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-500/10 text-red-500 border-red-500/20'
                }`}>
                    {message.type === 'success' ? <FiCheckCircle /> : <FiAlertCircle />}
                    <span>{message.text}</span>
                </div>
            )}

            <form onSubmit={handleSave} className="space-y-6">
                {/* Store Presence Section */}
                <div className="bg-background border border-foreground/10 rounded-xl overflow-hidden shadow-sm transition-all hover:shadow-md">
                    <div className="p-6 bg-foreground/5 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-xl bg-foreground/5 flex items-center justify-center text-foreground group">
                                <FiGlobe size={24} strokeWidth={1.5} className="group-hover:rotate-12 transition-transform" />
                            </div>
                            <div>
                                <h2 className="text-lg font-bold text-foreground">{t('admin.management.payment.store.title')}</h2>
                                <p className="text-xs text-foreground/50 font-medium">{t('admin.management.payment.store.subtitle')}</p>
                            </div>
                        </div>
                    </div>
                    <div className="p-8 border-t border-foreground/5 bg-foreground/[0.02]">
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold uppercase tracking-[0.2em] text-foreground/40">{t('admin.management.payment.store.urlLabel')}</label>
                            <div className="relative">
                                <input 
                                    type="text"
                                    className="w-full bg-background border border-foreground/10 rounded-lg px-4 py-3 text-sm font-mono focus:outline-none focus:ring-2 focus:ring-foreground/5 transition-all text-foreground placeholder:text-foreground/20"
                                    placeholder="e.g. https://yourstore.com"
                                    value={settings.storeUrl || ''}
                                    onChange={(e) => setSettings({
                                        ...settings,
                                        storeUrl: e.target.value
                                    })}
                                />
                                <div className="absolute right-3 top-1/2 -translate-y-1/2 text-foreground/20">
                                    <FiExternalLink size={16} />
                                </div>
                            </div>
                            <p className="text-[10px] text-foreground/30 font-medium italic mt-2">
                                {t('admin.management.payment.store.urlHint')}
                            </p>
                        </div>
                    </div>
                </div>

                {/* PayPal Section */}
                <div className="bg-background border border-foreground/10 rounded-xl overflow-hidden shadow-sm transition-all hover:shadow-md">
                    <div className="p-6 bg-foreground/5 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-xl bg-foreground/5 flex items-center justify-center text-foreground group">
                                <FiCreditCard size={24} strokeWidth={1.5} className="group-hover:scale-110 transition-transform" />
                            </div>
                            <div>
                                <h2 className="text-lg font-bold text-foreground">{t('admin.management.payment.paypal.title')}</h2>
                                <p className="text-xs text-foreground/50 font-medium">{t('admin.management.payment.paypal.subtitle')}</p>
                            </div>
                        </div>
                        <label className="relative inline-flex items-center cursor-pointer group">
                            <input 
                                type="checkbox" 
                                className="sr-only peer"
                                checked={settings.paypal?.active || false}
                                onChange={(e) => setSettings({
                                    ...settings,
                                    paypal: { ...settings.paypal, active: e.target.checked }
                                })}
                            />
                            <div className="w-14 h-7 bg-foreground/20 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-background after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-background after:border-foreground/10 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-foreground"></div>
                        </label>
                    </div>

                    <AnimatePresence>
                        {settings.paypal?.active && (
                            <motion.div
                                initial={{ height: 0, opacity: 0 }}
                                animate={{ height: 'auto', opacity: 1 }}
                                exit={{ height: 0, opacity: 0 }}
                                transition={{ duration: 0.4, ease: [0.23, 1, 0.32, 1] }}
                                className="overflow-hidden border-t border-foreground/5"
                            >
                                <div className="p-8 space-y-8">
                                    <div className="grid md:grid-cols-2 gap-8">
                                        <div className="space-y-2">
                                            <label className="text-[10px] font-bold uppercase tracking-[0.2em] text-foreground/40">{t('admin.management.payment.paypal.envLabel')}</label>
                                            <select 
                                                className="w-full bg-background border border-foreground/10 rounded-lg px-4 py-3 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-foreground/5 transition-all text-foreground"
                                                value={settings.paypal?.mode || 'sandbox'}
                                                onChange={(e) => setSettings({
                                                    ...settings,
                                                    paypal: { ...settings.paypal, mode: e.target.value as 'sandbox' | 'live' }
                                                })}
                                            >
