import { useState, useRef } from 'react';
import api from '@/lib/api';
import { FiUpload, FiX, FiPlus, FiImage } from 'react-icons/fi';

interface MultipleImageUploadProps {
  mainImage?: string;
  images?: string[];
  onMainImageChange: (url: string) => void;
  onImagesChange: (urls: string[]) => void;
}

export default function MultipleImageUpload({
  mainImage,
  images = [],
  onMainImageChange,
  onImagesChange,
}: MultipleImageUploadProps) {
  const [uploading, setUploading] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const mainImageInputRef = useRef<HTMLInputElement>(null);
  const additionalImageInputRef = useRef<HTMLInputElement>(null);

  const uploadImage = async (file: File): Promise<string> => {
    // Validate file type
    if (!file.type.startsWith('image/')) {
      throw new Error('Please select an image file');
    }

    // Validate file size (5MB)
    if (file.size > 5 * 1024 * 1024) {
      throw new Error('Image size must be less than 5MB');
    }

    // Create form data
    const formData = new FormData();
    formData.append('image', file);

    // Upload image
    const response = await api.post('/upload/image', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });

    if (response.data.success) {
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || '';
      const baseUrl = apiUrl.replace(/\/api$/, '');
      return `${baseUrl}${response.data.data.url}`;
    } else {
      throw new Error(response.data.message || 'Failed to upload image');
    }
  };

  const handleMainImageSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setError(null);
    setUploading('main');

    try {
      const imageUrl = await uploadImage(file);
      onMainImageChange(imageUrl);
    } catch (err: any) {
      setError(err.message || 'Failed to upload main image');
    } finally {
      setUploading(null);
    }
  };

  const handleAdditionalImageSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    setError(null);
    setUploading('additional');

    try {
      const uploadPromises = files.map((file) => uploadImage(file));
      const uploadedUrls = await Promise.all(uploadPromises);
      onImagesChange([...images, ...uploadedUrls]);
    } catch (err: any) {
      setError(err.message || 'Failed to upload images');
    } finally {
      setUploading(null);
      if (additionalImageInputRef.current) {
        additionalImageInputRef.current.value = '';
      }
    }
  };

  const removeMainImage = () => {
    onMainImageChange('');
  };

  const removeAdditionalImage = (index: number) => {
    onImagesChange(images.filter((_, i) => i !== index));
  };

  return (
    <div className="grid md:grid-cols-2 gap-8">
      {/* Left: Main Image */}
      <div>
        <label className="block text-sm font-medium text-foreground/80 mb-2">
          Main Image <span className="text-red-500">*</span>
        </label>
        {mainImage ? (
          <div className="relative w-full aspect-square border border-border rounded-xl overflow-hidden group bg-muted">
            <img
              src={mainImage}
              alt="Main product image"
              className="w-full h-full object-cover"
              onError={(e) => {
                e.currentTarget.style.display = 'none';
                e.currentTarget.parentElement!.classList.add('flex', 'items-center', 'justify-center');
              }}
            />
            {/* Fallback for error */}
            <div className="hidden text-muted-foreground/80 flex-col items-center gap-2">
              <FiImage size={32} />
              <span>Image Error</span>
            </div>

            <button
              type="button"
              onClick={removeMainImage}
              className="absolute top-3 right-3 p-2 bg-background/90 text-red-600 rounded-lg shadow-sm hover:bg-red-50 transition-colors opacity-0 group-hover:opacity-100 backdrop-blur-sm"
              title="Remove Image"
            >
              <FiX size={18} />
            </button>
            <div className="absolute bottom-3 left-3 px-2 py-1 bg-foreground/70 text-background text-xs rounded backdrop-blur-md">
              Main Image
            </div>
          </div>
        ) : (
          <div
            className={`w-full aspect-square border-2 border-dashed rounded-xl flex flex-col items-center justify-center text-center transition-all duration-200 group ${uploading === 'main'
              ? 'border-border bg-muted'
              : 'border-border hover:border-foreground hover:bg-muted/50 cursor-pointer'
              }`}
            onClick={() => !uploading && mainImageInputRef.current?.click()}
          >
            <input
              ref={mainImageInputRef}
              type="file"
              accept="image/*"
              onChange={handleMainImageSelect}
              className="hidden"
              disabled={uploading === 'main'}
            />
            {uploading === 'main' ? (
              <div className="space-y-3">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-foreground mx-auto"></div>
                <p className="text-sm font-medium text-muted-foreground">Uploading...</p>
              </div>
            ) : (
              <div className="space-y-3">
                <div className="w-12 h-12 mx-auto rounded-full bg-muted/80 flex items-center justify-center group-hover:bg-foreground group-hover:text-background transition-colors text-muted-foreground">
                  <FiUpload size={24} />
                </div>
                <div>
                  <p className="text-sm font-medium text-foreground">Upload Main Image</p>
                  <p className="text-xs text-muted-foreground mt-1">PNG, JPG up to 5MB</p>
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Right: Additional Images (8 slots) */}
      <div>
        <label className="block text-sm font-medium text-foreground/80 mb-2">
          Gallery Images (Max 8)
        </label>
        <div className="grid grid-cols-4 gap-3">
          {/* Existing Images */}
          {images.slice(0, 8).map((imageUrl, index) => (
            <div key={index} className="relative aspect-square border border-border rounded-lg overflow-hidden group bg-muted">
              <img
                src={imageUrl}
                alt={`Gallery ${index + 1}`}
                className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
                onError={(e) => {
                  e.currentTarget.style.display = 'none';
                  e.currentTarget.parentElement!.classList.add('flex', 'items-center', 'justify-center');
                }}
              />
              <div className="hidden text-gray-300">
                <FiImage size={20} />
              </div>

              <button
                type="button"
                onClick={() => removeAdditionalImage(index)}
                className="absolute top-1 right-1 p-1 bg-background/90 text-red-600 rounded-md shadow-sm hover:bg-red-50 transition-colors opacity-0 group-hover:opacity-100 backdrop-blur-sm"
              >
                <FiX size={14} />
              </button>
            </div>
          ))}

          {/* Empty Slots + Upload Button */}
          {images.length < 8 && (
            <div
              className={`aspect-square border-2 border-dashed rounded-lg flex flex-col items-center justify-center transition-all duration-200 ${uploading === 'additional'
                ? 'border-border bg-muted'
                : 'border-border hover:border-foreground hover:bg-muted/50 cursor-pointer'
                }`}
              onClick={() => !uploading && additionalImageInputRef.current?.click()}
            >
              {uploading === 'additional' ? (
                <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-foreground"></div>
              ) : (
                <FiPlus size={24} className="text-muted-foreground/80" />
              )}
            </div>
          )}

          {/* Fill remaining slots with placeholders to keep grid structure if needed, or just leave empty space. 
               The design looks better if we just show the Add button. 
               But to match previous behavior of showing placeholders: */}
          {Array.from({ length: Math.max(0, 7 - images.length) }).map((_, i) => (
            <div key={`placeholder-${i}`} className="aspect-square border border-border rounded-lg bg-muted/50"></div>
          ))}

        </div>
        <input
          ref={additionalImageInputRef}
          type="file"
          accept="image/*"
          multiple
          onChange={handleAdditionalImageSelect}
          className="hidden"
          disabled={uploading === 'additional'}
        />
        <p className="mt-3 text-xs text-muted-foreground">
          Add up to 8 additional images to show different angles or details.
        </p>
      </div>

      {error && (
        <div className="md:col-span-2 p-4 bg-red-50 border border-red-200 rounded-xl text-red-600 text-sm flex items-center gap-2">
          <FiX size={16} />
          {error}
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useRef, useEffect } from 'react';
import api from '@/lib/api';
import { FiUpload, FiVideo, FiX, FiTrash2 } from 'react-icons/fi';

interface VideoUploadProps {
    value?: string;
    onChange: (url: string) => void;
    onRemove?: () => void;
    label?: string;
    required?: boolean;
}

export default function VideoUpload({ value, onChange, onRemove, label, required }: VideoUploadProps) {
    const [uploading, setUploading] = useState(false);
    const [preview, setPreview] = useState<string | null>(value || null);
    const [error, setError] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        setPreview(value || null);
    }, [value]);

    const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('video/')) {
            setError('Please select a video file');
            return;
        }

        if (file.size > 50 * 1024 * 1024) { // 50MB
            setError('Video size must be less than 50MB');
            return;
        }

        setError(null);
        setUploading(true);

        try {
            const formData = new FormData();
            formData.append('video', file);

            const response = await api.post('/upload/video', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                },
            });

            if (response.data.success) {
                const apiUrl = process.env.NEXT_PUBLIC_API_URL || '';
                const baseUrl = apiUrl.replace(/\/api$/, '');
                const videoUrl = `${baseUrl}${response.data.data.url}`;

                setPreview(videoUrl);
                onChange(videoUrl);
            } else {
                setError(response.data.message || 'Failed to upload video');
            }
        } catch (err: any) {
            setError(err.response?.data?.message || err.message || 'Failed to upload video');
        } finally {
            setUploading(false);
        }
    };

    const handleRemove = () => {
        setPreview(null);
        onChange('');
        if (onRemove) onRemove();
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    return (
        <div className="w-full">
            {label && (
                <label className="block text-sm font-medium text-foreground/80 mb-2">
                    {label} {required && <span className="text-red-500">*</span>}
                </label>
            )}

            <div className="space-y-4">
                {preview && (
                    <div className="relative group border border-border rounded-xl overflow-hidden shadow-sm bg-muted aspect-video">
                        <video
                            src={preview}
                            className="w-full h-full object-cover"
                            controls
                        />

                        <div className="absolute inset-0 bg-foreground/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3 z-10">
                            <button
                                type="button"
                                onClick={() => fileInputRef.current?.click()}
                                className="p-2 bg-background/10 text-background rounded-lg hover:bg-background/20 backdrop-blur-sm transition-colors"
                                title="Replace"
                            >
                                <FiUpload size={20} />
                            </button>
                            <button
                                type="button"
                                onClick={handleRemove}
                                className="p-2 bg-red-500/80 text-background rounded-lg hover:bg-red-600 backdrop-blur-sm transition-colors"
                                title="Remove"
                            >
                                <FiTrash2 size={20} />
                            </button>
                        </div>
                    </div>
                )}

                {!preview && (
                    <div
                        className={`group relative border-2 border-dashed rounded-xl p-8 text-center transition-all duration-200 w-full ${uploading
                            ? 'border-border bg-muted'
                            : 'border-border hover:border-foreground hover:bg-muted/50 cursor-pointer'
                            } ${error ? 'border-red-300 bg-red-50/10' : ''}`}
                        onClick={() => !uploading && fileInputRef.current?.click()}
                    >
                        <input
                            ref={fileInputRef}
                            type="file"
                            accept="video/*"
                            onChange={handleFileSelect}
                            className="hidden"
                            disabled={uploading}
                        />

                        {uploading ? (
                            <div className="py-4 space-y-3">
                                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-foreground mx-auto"></div>
                                <p className="text-sm font-medium text-muted-foreground">Uploading Video...</p>
                            </div>
                        ) : (
                            <div className="py-4 space-y-3">
                                <div className="w-12 h-12 mx-auto rounded-full bg-muted/80 flex items-center justify-center group-hover:bg-foreground group-hover:text-background transition-colors text-muted-foreground">
                                    <FiVideo size={20} />
                                </div>
                                <div>
                                    <p className="text-sm font-medium text-foreground">Click to upload video</p>
                                    <p className="text-xs text-muted-foreground mt-1">MP4, WEBM, OGG (max. 50MB)</p>
                                </div>
                            </div>
                        )}
                    </div>
                )}

                {error && (
                    <div className="flex items-center gap-2 p-3 bg-red-50 border border-red-100 rounded-lg text-red-600 text-sm">
                        <FiX size={16} />
                        {error}
                    </div>
                )}
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAppDispatch, useAppSelector } from '@/lib/hooks';
import { createBlog, updateBlog, fetchBlogBySlug } from '@/lib/slices/blogSlice';
import api from '@/lib/api';
import { FiArrowLeft, FiSave, FiImage, FiType, FiAlignLeft, FiUpload, FiBold, FiItalic, FiList, FiLink } from 'react-icons/fi';
import { useEditor, EditorContent } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import Link from '@tiptap/extension-link';
import { useTranslation } from '@/hooks/useTranslation';

interface BlogEditorProps {
    id?: string; // If present, edit mode
}

const MenuBar = ({ editor }: { editor: any }) => {
    const { t } = useTranslation();
    if (!editor) {
        return null;
    }

    const setLink = () => {
        const previousUrl = editor.getAttributes('link').href;
        const url = window.prompt('URL', previousUrl);

        if (url === null) {
            return;
        }

        if (url === '') {
            editor.chain().focus().extendMarkRange('link').unsetLink().run();
            return;
        }

        editor.chain().focus().extendMarkRange('link').setLink({ href: url }).run();
    };

    return (
        <div className="flex flex-wrap gap-1 p-2 bg-gray-50 border-b border-gray-200">
            <button
                type="button"
                onClick={() => editor.chain().focus().toggleBold().run()}
                className={`p-2 rounded hover:bg-gray-200 transition-colors ${editor.isActive('bold') ? 'bg-gray-200 text-black' : 'text-gray-500'}`}
                title={t('admin.content.journal.editor.menubar.bold')}
            >
                <FiBold size={16} />
            </button>
            <button
                type="button"
                onClick={() => editor.chain().focus().toggleItalic().run()}
                className={`p-2 rounded hover:bg-gray-200 transition-colors ${editor.isActive('italic') ? 'bg-gray-200 text-black' : 'text-gray-500'}`}
                title={t('admin.content.journal.editor.menubar.italic')}
            >
                <FiItalic size={16} />
            </button>
            <div className="w-px h-6 bg-gray-300 mx-1 self-center" />
            <button
                type="button"
                onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()}
                className={`p-2 rounded hover:bg-gray-200 transition-colors px-3 text-xs font-bold ${editor.isActive('heading', { level: 2 }) ? 'bg-gray-200 text-black' : 'text-gray-500'}`}
            >
                H2
            </button>
            <button
                type="button"
                onClick={() => editor.chain().focus().toggleHeading({ level: 3 }).run()}
                className={`p-2 rounded hover:bg-gray-200 transition-colors px-3 text-xs font-bold ${editor.isActive('heading', { level: 3 }) ? 'bg-gray-200 text-black' : 'text-gray-500'}`}
            >
                H3
            </button>
            <div className="w-px h-6 bg-gray-300 mx-1 self-center" />
            <button
                type="button"
                onClick={() => editor.chain().focus().toggleBulletList().run()}
                className={`p-2 rounded hover:bg-gray-200 transition-colors ${editor.isActive('bulletList') ? 'bg-gray-200 text-black' : 'text-gray-500'}`}
                title={t('admin.content.journal.editor.menubar.bulletList')}
            >
                <FiList size={16} />
            </button>
            <button
                type="button"
                onClick={setLink}
                className={`p-2 rounded hover:bg-gray-200 transition-colors ${editor.isActive('link') ? 'bg-gray-200 text-black' : 'text-gray-500'}`}
                title={t('admin.content.journal.editor.menubar.link')}
            >
                <FiLink size={16} />
            </button>
            <button
                type="button"
                onClick={() => editor.chain().focus().unsetAllMarks().clearNodes().run()}
                className="p-2 rounded hover:bg-red-50 text-gray-400 hover:text-red-500 transition-colors ml-auto"
                title={t('admin.content.journal.editor.menubar.clear')}
            >
                {t('admin.content.journal.editor.menubar.clear')}
            </button>
        </div>
    );
};

export default function BlogEditor({ id }: BlogEditorProps) {
    const { t } = useTranslation();
    const router = useRouter();
    const dispatch = useAppDispatch();
    const { blog, loading: blogLoading } = useAppSelector((state) => state.blog);
    const isBlogLoading = blogLoading.fetchOne;

    const [formData, setFormData] = useState({
        title: '',
        excerpt: '',
        content: '',
        image: '',
        tags: '',
        isPublished: false
    });
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [uploadingImage, setUploadingImage] = useState(false);

    const editor = useEditor({
        extensions: [
            StarterKit,
            Link.configure({
                openOnClick: false,
                HTMLAttributes: {
                    class: 'text-blue-600 underline cursor-pointer',
                },
            }),
        ],
        content: '',
        immediatelyRender: false,
        onUpdate: ({ editor }) => {
            setFormData(prev => ({ ...prev, content: editor.getHTML() }));
        },
        editorProps: {
            attributes: {
                class: 'prose prose-sm sm:prose-base lg:prose-lg xl:prose-2xl focus:outline-none min-h-[400px] p-6 max-w-none hover:prose-a:text-blue-800 transition-colors',
            },
        },
    });

    useEffect(() => {
        if (id) {
            dispatch(fetchBlogBySlug(id));
        }
    }, [id, dispatch]);

    useEffect(() => {
        if (id && blog) {
            setFormData({
                title: blog.title || '',
                excerpt: blog.excerpt || '',
                content: blog.content || '',
                image: blog.image || '',
                tags: blog.tags?.join(', ') || '',
                isPublished: blog.isPublished || false
            });
            if (editor && blog.content) {
                editor.commands.setContent(blog.content);
            }
        }
    }, [id, blog, editor]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleCheckboxChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, checked } = e.target;
        setFormData(prev => ({ ...prev, [name]: checked }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);

        const payload = {
            ...formData,
            tags: formData.tags.split(',').map(t => t.trim()).filter(Boolean)
        };

        try {
            if (id) {
                await dispatch(updateBlog({ id, data: payload })).unwrap();
            } else {
                await dispatch(createBlog(payload)).unwrap();
            }
            router.push('/admin/journal');
        } catch (err) {
            console.error('Failed to save story:', err);
            alert(t('admin.content.journal.errors.save'));
        } finally {
            setIsSubmitting(false);
        }
    };

    if (id && isBlogLoading && !blog) {
        return (
            <div className="flex justify-center py-20">
                <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-black"></div>
            </div>
        );
    }

    return (
        <div className="max-w-4xl mx-auto pb-20 animate-in fade-in duration-500">
            <div className="flex items-center justify-between mb-8">
                <button onClick={() => router.back()} className="flex items-center gap-2 text-gray-500 hover:text-black transition-colors uppercase text-[10px] font-bold tracking-widest">
                    <FiArrowLeft /> {t('admin.content.journal.editor.back')}
                </button>
                <h1 className="text-2xl font-bold tracking-tight text-gray-900">{id ? t('admin.content.journal.editor.editTitle') : t('admin.content.journal.editor.newTitle')}</h1>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
                <div className="bg-white p-8 rounded-xl border border-gray-100 shadow-sm space-y-6">

                    {/* Title */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2">
                            <FiType /> {t('admin.content.journal.editor.fields.title')}
                        </label>
                        <input
                            type="text"
                            name="title"
                            value={formData.title}
                            onChange={handleChange}
                            required
                            className="w-full text-3xl font-serif border-0 border-b border-gray-100 focus:border-black focus:ring-0 px-0 py-4 placeholder:text-gray-200 transition-all font-light"
                            placeholder={t('admin.content.journal.editor.fields.titlePlaceholder')}
                        />
                    </div>

                    {/* Excerpt */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2">
                            {t('admin.content.journal.editor.fields.summary')}
                        </label>
                        <textarea
                            name="excerpt"
                            value={formData.excerpt}
                            onChange={handleChange}
                            required
                            rows={2}
                            className="w-full border border-gray-100 rounded-lg p-4 focus:border-black focus:ring-0 transition-all text-sm text-gray-600 font-light resize-none"
                            placeholder={t('admin.content.journal.editor.fields.summaryPlaceholder')}
                        />
                    </div>

                    {/* Image Upload */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2">
                            <FiImage /> {t('admin.content.journal.editor.fields.coverImage')}
                        </label>
                        <div className="border border-gray-100 rounded-lg p-2 bg-gray-50/50">
                            {formData.image ? (
                                <div className="space-y-4">
                                    <div className="aspect-[21/9] bg-white rounded-lg overflow-hidden border border-gray-100 relative group">
                                        <img src={formData.image} alt="Preview" className="w-full h-full object-cover" />
                                        <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all backdrop-blur-[2px]">
                                            <button
                                                type="button"
                                                onClick={() => setFormData(prev => ({ ...prev, image: '' }))}
                                                className="bg-white text-black text-[10px] font-bold uppercase tracking-widest px-6 py-2.5 rounded-sm hover:bg-black hover:text-white transition-all shadow-xl"
                                            >
                                                {t('admin.content.journal.editor.fields.replaceButton')}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div className="border border-dashed border-gray-200 rounded-lg p-10 text-center hover:border-black hover:bg-white transition-all group bg-white/50">
                                    {uploadingImage ? (
                                        <div className="flex flex-col items-center gap-3">
                                            <div className="w-6 h-6 border-2 border-black border-t-transparent rounded-full animate-spin"></div>
                                            <p className="text-[10px] font-bold uppercase tracking-widest text-gray-400">{t('admin.content.journal.editor.fields.uploading')}</p>
                                        </div>
                                    ) : (
                                        <label className="cursor-pointer flex flex-col items-center gap-3">
                                            <div className="w-12 h-12 rounded-full bg-gray-50 flex items-center justify-center group-hover:bg-black group-hover:text-white transition-all duration-500">
                                                <FiUpload size={20} />
                                            </div>
                                            <span className="text-xs font-bold uppercase tracking-widest text-gray-900">{t('admin.content.journal.editor.fields.uploadButton')}</span>
                                            <span className="text-[10px] text-gray-400 uppercase tracking-[0.2em]">{t('admin.content.journal.editor.fields.uploadHint')}</span>
                                            <input
                                                type="file"
                                                accept="image/*"
                                                className="hidden"
                                                onChange={async (e) => {
                                                    const file = e.target.files?.[0];
                                                    if (!file) return;

                                                    setUploadingImage(true);
                                                    const data = new FormData();
                                                    data.append('image', file);

                                                    try {
                                                        const res = await api.post('/upload/image', data, {
                                                            headers: { 'Content-Type': 'multipart/form-data' }
                                                        });
                                                        const imageUrl = res.data.data.url.startsWith('http')
                                                            ? res.data.data.url
                                                            : `${process.env.NEXT_PUBLIC_API_URL?.replace('/api', '')}${res.data.data.url}`;

                                                        setFormData(prev => ({ ...prev, image: imageUrl }));
                                                    } catch (err) {
                                                        console.error('Upload failed:', err);
                                                        alert(t('admin.content.journal.errors.upload'));
                                                    } finally {
                                                        setUploadingImage(false);
                                                    }
                                                }}
                                            />
                                        </label>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Content */}
                    <div className="space-y-2">
                        <label className="text-xs font-bold uppercase tracking-widest text-gray-400 flex items-center gap-2">
                            <FiAlignLeft /> {t('admin.content.journal.editor.fields.content')}
                        </label>
                        <div className="border border-gray-100 rounded-xl overflow-hidden shadow-sm ring-1 ring-gray-100">
                            <MenuBar editor={editor} />
                            <EditorContent editor={editor} />
                        </div>
                    </div>

                    {/* Tags & Status */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-6 border-t border-gray-50">
                        <div className="space-y-2">
                            <label className="text-xs font-bold uppercase tracking-widest text-gray-400">{t('admin.content.journal.editor.fields.tags')}</label>
                            <input
                                type="text"
                                name="tags"
                                value={formData.tags}
                                onChange={handleChange}
                                className="w-full border border-gray-100 rounded-lg p-3 focus:border-black focus:ring-0 transition-all text-sm font-light bg-gray-50/50"
                                placeholder={t('admin.content.journal.editor.fields.tagsPlaceholder')}
                            />
                        </div>
                        <div className="flex items-center justify-between p-4 bg-gray-50/50 rounded-lg border border-gray-50">
                            <span className="text-xs font-bold uppercase tracking-widest text-gray-900">{t('admin.content.journal.editor.fields.publishNow')}</span>
                            <label className="relative inline-flex items-center cursor-pointer">
                                <input
                                    type="checkbox"
                                    name="isPublished"
                                    checked={formData.isPublished}
                                    onChange={handleCheckboxChange}
                                    className="sr-only peer"
                                />
                                <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-black"></div>
                            </label>
                        </div>
                    </div>

                </div>

                <div className="flex justify-end gap-3 flex-col sm:flex-row">
                    <button
                        type="button"
                        onClick={() => router.back()}
                        className="px-8 py-4 border border-gray-200 rounded-sm font-bold text-gray-400 hover:text-black hover:border-black transition-all uppercase text-[10px] tracking-widest"
                    >
                        {t('admin.content.journal.editor.actions.discard')}
                    </button>
                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className="px-10 py-4 bg-black text-white rounded-sm font-bold hover:bg-zinc-800 transition-all uppercase text-[10px] tracking-widest flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed shadow-xl shadow-black/10"
                    >
                        <FiSave size={14} />
                        {isSubmitting ? t('admin.content.journal.editor.actions.saving') : t('admin.content.journal.editor.actions.save')}
                    </button>
                </div>
            </form>
        </div>
    );
}

